1	const PROCESSING_FEE = 5;
2	const FIRST_CONTRACT_INSURANCE_RATE = 0.1;
3	const LOYALTY_DISCOUNT_RATE = 0.2;
4	const LOYALTY_THRESHOLD_YEARS = 2;
5	const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15;
6	const COMPONENT_BASE_PREMIUM = 25;
7	const COMPONENT_INSURANCE_VALUE = 250;
8	const BUILDING_BLOCK_SIZE = 3;
9	const BUILDING_BLOCK_BASE_PREMIUM = 60;
10	const CURSE_SURCHARGE_RATE = 0.5;
11	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
12	const HIGH_ENCHANTMENT_THRESHOLD = 5;
13	const DEDUCTIBLE_PER_DAMAGE = 100;
14	const CAP_MULTIPLIER = 2;
15	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
16	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
17	
18	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
19	type Customer = { yearsWithMHPCO: number };
20	type Damage = { itemType: string; amount: number };
21	type Incident = { cause: string; damages: Damage[] };
22	type QuoteStep = { op: "quote"; items: Item[] };
23	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
24	type Step = QuoteStep | ClaimStep;
25	type Scenario = { customer: Customer; steps: Step[] };
26	
27	type QuoteResult = { premium: number };
28	type ClaimResult = { payout: number; remainingCap: number };
29	type StepResult = QuoteResult | ClaimResult;
30	
31	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	};
37	
38	const MAIN_ITEM_INSURANCE_VALUE: Record<string, number> = {
39	  sword: 1000,
40	  amulet: 600,
41	  staff: 800,
42	  potion: 400,
43	};
44	
45	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
46	
47	const isComponent = (type: string) => COMPONENT_TYPES.has(type);
48	
49	const itemInsuranceValue = (item: Item): number =>
50	  isComponent(item.type) ? COMPONENT_INSURANCE_VALUE : MAIN_ITEM_INSURANCE_VALUE[item.type];
51	
52	const componentsGroupBase = (count: number): number => {
53	  if (count === BUILDING_BLOCK_SIZE) return BUILDING_BLOCK_BASE_PREMIUM;
54	  return count * COMPONENT_BASE_PREMIUM;
55	};
56	
57	const itemBasePremium = (item: Item): number => {
58	  if (isComponent(item.type)) return COMPONENT_BASE_PREMIUM;
59	  return MAIN_ITEM_BASE_PREMIUM[item.type];
60	};
61	
62	const enchantmentLevel = (item: Item | undefined): number => item?.enchantment ?? 0;
63	
64	const itemSurcharges = (item: Item): number => {
65	  if (isComponent(item.type)) return 0;
66	  const base = itemBasePremium(item);
67	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
68	  const highEnchantment =
69	    enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD
70	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
71	      : 0;
72	  return curse + highEnchantment;
73	};
74	
75	const sum = (values: number[]): number => values.reduce((a, b) => a + b, 0);
76	
77	const countByType = (items: Item[]): Map<string, number> =>
78	  items.reduce((counts, item) => {
79	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
80	    return counts;
81	  }, new Map<string, number>());
82	
83	const policyBaseSum = (items: Item[]): number => {
84	  const mainItems = items.filter((i) => !isComponent(i.type));
85	  const components = items.filter((i) => isComponent(i.type));
86	  const mainSum = sum(mainItems.map(itemBasePremium));
87	  const componentsSum = sum(
88	    Array.from(countByType(components).values(), componentsGroupBase)
89	  );
90	  return mainSum + componentsSum;
91	};
92	
93	const policyItemSurcharges = (items: Item[]): number => sum(items.map(itemSurcharges));
94	
95	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
96	  const baseSum = policyBaseSum(items);
97	  const surcharges = policyItemSurcharges(items);
98	  const firstContractInsurance = baseSum * FIRST_CONTRACT_INSURANCE_RATE;
99	  const loyaltyDiscount =
100	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? baseSum * LOYALTY_DISCOUNT_RATE : 0;
101	  const followUpDiscount = isFollowUp ? baseSum * FOLLOW_UP_CONTRACT_DISCOUNT_RATE : 0;
102	  return Math.ceil(
103	    baseSum + surcharges + firstContractInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE
104	  );
105	};
106	
107	type Policy = { items: Item[]; cap: number };
108	
109	const createPolicy = (items: Item[]): Policy => {
110	  const insuranceSum = sum(items.map(itemInsuranceValue));
111	  return { items, cap: insuranceSum * CAP_MULTIPLIER };
112	};
113	
114	const qualifiesForHighEnchantmentClaim = (item: Item | undefined): boolean =>
115	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
116	
117	const reimbursableAmount = (damage: Damage, item: Item | undefined): number =>
118	  qualifiesForHighEnchantmentClaim(item)
119	    ? damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE
120	    : damage.amount;
121	
122	const damagePayout = (damage: Damage, items: Item[]): number => {
123	  const damagedItem = items.find((i) => i.type === damage.itemType);
124	  const reimbursable = reimbursableAmount(damage, damagedItem);
125	  return Math.max(0, reimbursable - DEDUCTIBLE_PER_DAMAGE);
126	};
127	
128	const countDamagesByType = (damages: Damage[]): Map<string, number> =>
129	  damages.reduce((counts, d) => {
130	    counts.set(d.itemType, (counts.get(d.itemType) ?? 0) + 1);
131	    return counts;
132	  }, new Map<string, number>());
133	
134	const validateDamagesAgainstPolicy = (policy: Policy, damages: Damage[]): void => {
135	  const policyCounts = countByType(policy.items);
136	  const damageCounts = countDamagesByType(damages);
137	  for (const [itemType, damageCount] of damageCounts) {
138	    if (damageCount > (policyCounts.get(itemType) ?? 0)) {
139	      throw new Error(
140	        `Claim rejected: ${damageCount} damages for ${itemType} but policy covers only ${policyCounts.get(itemType) ?? 0}`,
141	      );
142	    }
143	  }
144	};
145	
146	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
147	  validateDamagesAgainstPolicy(policy, incident.damages);
148	  const rawPayout = sum(incident.damages.map((d) => damagePayout(d, policy.items)));
149	  const payout = Math.min(rawPayout, policy.cap);
150	  policy.cap -= payout;
151	  return { payout: Math.floor(payout), remainingCap: policy.cap };
152	};
153	
154	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
155	  const policies: Policy[] = [];
156	  let quoteCount = 0;
157	  const results: StepResult[] = scenario.steps.map((step) => {
158	    if (step.op === "quote") {
159	      const isFollowUp = quoteCount > 0;
160	      quoteCount++;
161	      policies.push(createPolicy(step.items));
162	      return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
163	    }
164	    return processClaim(policies[step.policy], step.incident);
165	  });
166	  return { results };
167	};
