  const damageCounts = countDamagesByType(damages);
  for (const [itemType, damageCount] of damageCounts) {
    if (damageCount > (policyCounts.get(itemType) ?? 0)) {
      throw new Error(
        `Claim rejected: ${damageCount} damages for ${itemType} but policy covers only ${policyCounts.get(itemType) ?? 0}`,
      );
    }
  }
};

